class {{nama_class}}:
    """Thread-safe SQLite connection pool."""
    def __init__(self, db_path, pool_size={{pool_size}}):
        self.db_path = db_path
        self.pool_size = pool_size
        self._pool = queue.Queue(maxsize=pool_size)
        self._lock = threading.Lock()
        self._created = 0
        for _ in range(pool_size):
            self._pool.put_nowait(self._new_conn())

    def _new_conn(self):
        conn = sqlite3.connect(self.db_path, check_same_thread=False)
        conn.row_factory = sqlite3.Row
        return conn

    def get_connection(self, timeout=5):
        """Get a connection from pool. Blocks up to timeout seconds."""
        return self._pool.get(timeout=timeout)

    def return_connection(self, conn):
        """Return a connection back to the pool."""
        self._pool.put_nowait(conn)

    def execute(self, sql, params=None):
        """Convenience: get conn, execute, return conn, return result."""
        conn = self.get_connection()
        try:
            if params:
                cur = conn.execute(sql, params)
            else:
                cur = conn.execute(sql)
            conn.commit()
            return cur
        finally:
            self.return_connection(conn)

    def close_all(self):
        """Close all connections in pool."""
        while not self._pool.empty():
            conn = self._pool.get_nowait()
            conn.close()

def {{nama_fungsi}}(csv_path, db_path, table_name='{{table_name}}', delimiter=','):
    """Import CSV file into SQLite table. Auto-creates table with detected types.
    Returns number of rows imported.
    """
    with open(csv_path, 'r', encoding='utf-8') as f:
        reader = csv.DictReader(f, delimiter=delimiter)
        rows = list(reader)
    if not rows:
        return 0
    columns = list(rows[0].keys())
    col_types = {}
    for col in columns:
        values = [r[col] for r in rows if r[col]]
        if all(_is_int(v) for v in values):
            col_types[col] = 'INTEGER'
        elif all(_is_float(v) for v in values):
            col_types[col] = 'REAL'
        else:
            col_types[col] = 'TEXT'
    col_defs = ['id INTEGER PRIMARY KEY AUTOINCREMENT']
    for col in columns:
        col_defs.append(col + ' ' + col_types[col])
    with sqlite3.connect(db_path) as conn:
        conn.execute('CREATE TABLE IF NOT EXISTS ' + table_name + ' (' + ', '.join(col_defs) + ')')
        placeholders = ', '.join(['?'] * len(columns))
        sql = 'INSERT INTO ' + table_name + ' (' + ', '.join(columns) + ') VALUES (' + placeholders + ')'
        for row in rows:
            values = [_convert_value(row[c], col_types[c]) for c in columns]
            conn.execute(sql, values)
        conn.commit()
    return len(rows)


def _is_int(s):
    try:
        int(s)
        return True
    except (ValueError, TypeError):
        return False


def _is_float(s):
    try:
        float(s)
        return True
    except (ValueError, TypeError):
        return False


def _convert_value(val, col_type):
    if val == '' or val is None:
        return None
    if col_type == 'INTEGER':
        return int(val)
    if col_type == 'REAL':
        return float(val)
    return val
